sys_script.script:
(function executeRule(current, previous) {

    if (current.employee.nil()) return;

    // Get the sys_user sys_id from the employee reference
    var userID = current.employee.toString();

    // Check if they already have the role
    var roleCheck = new GlideRecord('sys_user_has_role');
    roleCheck.addQuery('user', userID);
    roleCheck.addQuery('role.name', 'x_1954179_employ_0.employee');
    roleCheck.query();

    if (!roleCheck.next()) {
        // Role not found, assign it
        var userRole = new GlideRecord('sys_user_has_role');
        userRole.initialize();
        userRole.user = userID;

        // Get the role sys_id
        var role = new GlideRecord('sys_user_role');
        role.addQuery('name', 'x_1954179_employ_0.employee');
        role.query();
        if (role.next()) {
            userRole.role = role.sys_id;
            userRole.insert();
            gs.info('Employee role assigned to user: ' + current.employee.getDisplayValue());
        }
    }

})(current, previous);
